<?php
declare(strict_types=1);
session_start();
function e($v){return htmlspecialchars((string)$v,ENT_QUOTES|ENT_SUBSTITUTE,'UTF-8');}
function db():PDO{static $p;if($p)return $p;foreach([__DIR__.'/../../database.php',__DIR__.'/../database.php'] as $f){if(is_file($f)){require_once $f;break;}}if(function_exists('ho_db'))$p=ho_db();elseif(($GLOBALS['pdo']??null) instanceof PDO)$p=$GLOBALS['pdo'];else throw new RuntimeException('No DB connection found. Expected ho_db() in database.php.');$p->setAttribute(PDO::ATTR_ERRMODE,PDO::ERRMODE_EXCEPTION);$p->setAttribute(PDO::ATTR_DEFAULT_FETCH_MODE,PDO::FETCH_ASSOC);return $p;}
function schema(PDO $p){$p->exec("CREATE TABLE IF NOT EXISTS wmt_settings(k VARCHAR(80) PRIMARY KEY,v LONGTEXT,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");$p->exec("CREATE TABLE IF NOT EXISTS wmt_associates(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL UNIQUE,team VARCHAR(40) NOT NULL DEFAULT 'Services',role_type VARCHAR(80) NOT NULL DEFAULT 'AP Service TA',can_cover TINYINT(1) NOT NULL DEFAULT 1,preferred_door ENUM('Grocery','GM','Either') NOT NULL DEFAULT 'Either',active TINYINT(1) NOT NULL DEFAULT 1,reliability DECIMAL(5,2) NOT NULL DEFAULT 3.00,notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");$p->exec("CREATE TABLE IF NOT EXISTS wmt_shifts(id INT AUTO_INCREMENT PRIMARY KEY,work_date DATE NOT NULL,associate_id INT NULL,associate_name VARCHAR(120) NOT NULL,team VARCHAR(40) NOT NULL DEFAULT 'Services',role_type VARCHAR(80) NOT NULL DEFAULT 'AP Service TA',start_time TIME NOT NULL,end_time TIME NOT NULL,notes TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,KEY d(work_date)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");$p->exec("CREATE TABLE IF NOT EXISTS wmt_tasks(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(180) NOT NULL UNIQUE,category VARCHAR(60) NOT NULL DEFAULT 'Entrance Readiness',priority ENUM('Critical','High','Medium','Low') NOT NULL DEFAULT 'Medium',weight INT NOT NULL DEFAULT 2,frequency VARCHAR(40) NOT NULL DEFAULT 'Daily',active TINYINT(1) NOT NULL DEFAULT 1,notes TEXT) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");$p->exec("CREATE TABLE IF NOT EXISTS wmt_turnins(id INT AUTO_INCREMENT PRIMARY KEY,work_date DATE NOT NULL,task_name VARCHAR(180) NOT NULL,status ENUM('Not Started','Completed','Missed','Deferred','N/A') NOT NULL DEFAULT 'Not Started',completed_by VARCHAR(120),notes TEXT,manager_signoff VARCHAR(120),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,KEY d(work_date)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");$p->exec("CREATE TABLE IF NOT EXISTS wmt_exceptions(id INT AUTO_INCREMENT PRIMARY KEY,work_date DATE NOT NULL,type VARCHAR(80) NOT NULL,post VARCHAR(20),start_time TIME,end_time TIME,associate_name VARCHAR(120),severity ENUM('Low','Medium','High','Critical') NOT NULL DEFAULT 'Medium',notes TEXT,reported_to VARCHAR(120),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,KEY d(work_date)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");seed($p);}
function setting(PDO $p,$k,$d=null){$s=$p->prepare('SELECT v FROM wmt_settings WHERE k=?');$s->execute([$k]);$v=$s->fetchColumn();return $v===false?$d:$v;}function setg(PDO $p,$k,$v){$p->prepare('INSERT INTO wmt_settings(k,v) VALUES(?,?) ON DUPLICATE KEY UPDATE v=VALUES(v)')->execute([$k,$v]);}
function seed(PDO $p){foreach(['triage_start'=>'08:00','triage_end'=>'17:00','grocery_gold_start'=>'06:00','grocery_gold_end'=>'23:00','gm_gold_start'=>'06:00','gm_gold_end'=>'21:00','slot_minutes'=>'15','ops_blackout_start'=>'10:00','ops_blackout_end'=>'12:00','ops_flex_per_person'=>'30','tl_flex_per_day'=>'15','investigator_flex'=>'never'] as $k=>$v)if(setting($p,$k)===null)setg($p,$k,$v);$tasks=[['Dust EAS pedestals','Entrance Readiness','Medium',2,'Daily'],['Cart wipes dispenser cleaned','Entrance Readiness','High',3,'Daily'],['Benches cleaned','Entrance Readiness','Medium',2,'Daily'],['Windows cleaned','Entrance Readiness','High',3,'Daily'],['Doors cleaned','Entrance Readiness','High',3,'Daily'],['Door track swept','Entrance Readiness','Medium',2,'Daily'],['Closets NCO','Organization','Low',1,'Daily/Weekly'],['Bottom of Mart Carts wiped','Entrance Readiness','High',4,'Daily'],['Vestibules clean and clear of spills/trash','Safety','Critical',5,'Continuous'],['Inclement weather response','Safety','Critical',5,'Triggered'],['Front entrance safety/security observation','Coverage','Critical',5,'Continuous'],['Greet, help, and thank customers','Service','High',3,'Continuous'],['Visual theft deterrence','Coverage','High',4,'Continuous'],['Merchandise protection device support','Merchandise Protection','Medium',3,'As Needed'],['Suspicious activity report/escalation','Reporting','High',2,'As Needed']];$q=$p->prepare('INSERT IGNORE INTO wmt_tasks(name,category,priority,weight,frequency) VALUES(?,?,?,?,?)');foreach($tasks as $t)$q->execute($t);}
function auth(PDO $p){$hash=setting($p,'admin_hash');if(!$hash){if(($_POST['form']??'')==='setpass'&&strlen($_POST['password']??'')>=8){setg($p,'admin_hash',password_hash($_POST['password'],PASSWORD_DEFAULT));$_SESSION['wmt']=1;header('Location:index.php');exit;}login('Create WMT admin password','setpass');}if(isset($_GET['logout'])){unset($_SESSION['wmt']);header('Location:index.php');exit;}if(($_POST['form']??'')==='login'&&password_verify($_POST['password']??'',$hash)){$_SESSION['wmt']=1;header('Location:index.php');exit;}if(empty($_SESSION['wmt']))login('AP Services login','login');}
function login($title,$form){?><!doctype html><title><?=e($title)?></title><style>body{font-family:system-ui;background:#f4f1ea}.box{max-width:420px;margin:12vh auto;background:#fff;padding:28px;border-radius:18px;border:1px solid #ddd}input,button{width:100%;padding:12px;border-radius:10px;margin-top:10px}button{background:#223b2a;color:#fff;font-weight:800}</style><div class=box><h1><?=e($title)?></h1><form method=post><input type=hidden name=form value=<?=e($form)?>><input type=password name=password placeholder="Password" required><button>Continue</button></form></div><?php exit;}
function mins($t){preg_match('/^(\d{1,2}):(\d{2})/',$t,$m);return ((int)($m[1]??0))*60+(int)($m[2]??0);}function tm($m){$m=(($m%1440)+1440)%1440;return sprintf('%02d:%02d',intdiv($m,60),$m%60);}function nice($m){$h=intdiv($m,60);$ap=$h>=12?'PM':'AM';$hh=$h%12?:12;return $hh.':'.sprintf('%02d',$m%60).$ap;}
function team($r){$x=strtolower(($r['team']??'').' '.($r['role_type']??''));if(str_contains($x,'invest'))return'Investigator';if(str_contains($x,'lead')||str_contains($x,'tl'))return'Team Lead';if(str_contains($x,'ops'))return'Ops';return'Services';}
function breaks($s){$st=mins(substr($s['start_time'],0,5));$en=mins(substr($s['end_time'],0,5));if($en<=$st)$en+=1440;$dur=$en-$st;$out=[];$round=fn($x)=>round($x/15)*15;if($dur>=480){$q=$dur/4;$out[]=['Break 1',$round($st+$q-8),15];$out[]=['Lunch',$round($st+2*$q-30),60];$out[]=['Break 2',$round($st+3*$q-8),15];}elseif($dur>=360){$out[]=['Break',$round($st+$dur/3-8),15];$out[]=['Lunch',$round($st+$dur*2/3-15),30];}elseif($dur>=240){$out[]=['Break',$round($st+$dur/2-8),15];}return $out;}
function off($s,$a,$b){foreach(breaks($s) as $w){if($a<$w[1]+$w[2]&&$b>$w[1])return $w[0];}return'';}function on($s,$a,$b){$st=mins(substr($s['start_time'],0,5));$en=mins(substr($s['end_time'],0,5));if($en<=$st)$en+=1440;return $a>=$st&&$b<=$en&&!off($s,$a,$b);}
function shifts(PDO $p,$d){$q=$p->prepare('SELECT s.*,a.preferred_door,a.can_cover,a.reliability FROM wmt_shifts s LEFT JOIN wmt_associates a ON a.id=s.associate_id WHERE work_date=? ORDER BY start_time,associate_name');$q->execute([$d]);return$q->fetchAll();}
function pick($c,$door,$used,$cnt){$best=null;$score=999999;foreach($c as $r){$n=$r['associate_name'];if(isset($used[$n]))continue;$s=($cnt[$n]??0)*5-((float)($r['reliability']??3))*2;if(($r['preferred_door']??'Either')===$door)$s-=20;elseif(($r['preferred_door']??'Either')==='Either')$s-=5;if($s<$score){$score=$s;$best=$r;}}return$best;}
function plan(PDO $p,$d){$rows=[];$sh=shifts($p,$d);$slot=(int)setting($p,'slot_minutes',15);$st=mins(setting($p,'triage_start','08:00'));$en=mins(setting($p,'triage_end','17:00'));$opsB=mins(setting($p,'ops_blackout_start','10:00'));$opsE=mins(setting($p,'ops_blackout_end','12:00'));$opsMax=(int)setting($p,'ops_flex_per_person',30);$tlMax=(int)setting($p,'tl_flex_per_day',15);$cnt=$opsUsed=[];$tlUsed=$gap=$req=$cov=$float=0;for($t=$st;$t<$en;$t+=$slot){$u=$br=[];foreach($sh as $s){$ss=mins(substr($s['start_time'],0,5));$ee=mins(substr($s['end_time'],0,5));if($ee<=$ss)$ee+=1440;if($t>=$ss&&$t+$slot<=$ee){$o=off($s,$t,$t+$slot);$o?$br[]=$s['associate_name'].' '.$o:$u[]=$s;}}$svc=array_values(array_filter($u,fn($x)=>team($x)==='Services'&&(int)($x['can_cover']??1)));$ops=array_values(array_filter($u,fn($x)=>team($x)==='Ops'));$tls=array_values(array_filter($u,fn($x)=>team($x)==='Team Lead'));$used=[];$g=pick($svc,'Grocery',$used,$cnt);if($g){$used[$g['associate_name']]=1;$cnt[$g['associate_name']]=($cnt[$g['associate_name']]??0)+1;}$gm=pick($svc,'GM',$used,$cnt);if($gm){$used[$gm['associate_name']]=1;$cnt[$gm['associate_name']]=($cnt[$gm['associate_name']]??0)+1;}$flex=[];foreach(['Grocery'=>&$g,'GM'=>&$gm] as $door=>&$target){if($target)continue;if(count($ops)>=2&&!($t<$opsE&&$t+$slot>$opsB)){foreach($ops as $o){$n=$o['associate_name'];if(!isset($used[$n])&&($opsUsed[$n]??0)+$slot<=$opsMax){$target=$o;$used[$n]=1;$opsUsed[$n]=($opsUsed[$n]??0)+$slot;$flex[]="$n Ops flex";break;}}}if(!$target&&$tlUsed+$slot<=$tlMax&&$tls){foreach($tls as $tl){$n=$tl['associate_name'];if(!isset($used[$n])){$target=$tl;$used[$n]=1;$tlUsed+=$slot;$flex[]="$n TL flex";break;}}}}$fl='';foreach($svc as $s){if(!isset($used[$s['associate_name']])){$fl=$s['associate_name'];$float+=$slot;break;}}$req+=2*$slot;$note=[];if(!$g){$gap+=$slot;$note[]='Grocery gap';}else$cov+=$slot;if(!$gm){$gap+=$slot;$note[]='GM gap'.(($t<$opsE&&$t+$slot>$opsB)?' (Ops lunch blackout)':'');}else$cov+=$slot;$rows[]=[$t,$t+$slot,$g['associate_name']??'',$gm['associate_name']??'',$fl,implode(', ',$br),implode(', ',$flex),implode('; ',$note)];}return compact('d','sh','rows','gap','req','cov','float','opsUsed','tlUsed')+['pct'=>$req?round($cov/$req*100,1):0];}
function upAssoc(PDO $p,$a){$name=trim($a['name']??$a['associate_name']??'');if(!$name)return 0;$team=$a['team']??'Services';$role=$a['role_type']??($a['role']??'AP Service TA');$pref=in_array(($a['preferred_door']??'Either'),['Grocery','GM','Either'])?$a['preferred_door']:'Either';$can=team(['team'=>$team,'role_type'=>$role])==='Investigator'?0:1;$p->prepare('INSERT INTO wmt_associates(name,team,role_type,can_cover,preferred_door,notes) VALUES(?,?,?,?,?,?) ON DUPLICATE KEY UPDATE team=VALUES(team),role_type=VALUES(role_type),can_cover=VALUES(can_cover),preferred_door=VALUES(preferred_door),notes=VALUES(notes)')->execute([$name,$team,$role,$can,$pref,$a['notes']??null]);$id=(int)$p->lastInsertId();if(!$id){$q=$p->prepare('SELECT id FROM wmt_associates WHERE name=?');$q->execute([$name]);$id=(int)$q->fetchColumn();}return$id;}
function post(PDO $p){if($_SERVER['REQUEST_METHOD']!=='POST')return'';$f=$_POST['form']??'';if($f==='json'){$j=json_decode($_POST['payload']??'',true);if(!is_array($j))return'Bad JSON';foreach($j['settings']??[] as $k=>$v)setg($p,$k,is_scalar($v)?(string)$v:json_encode($v));foreach($j['associates']??[] as $a)upAssoc($p,$a);foreach($j['replace_schedule_dates']??[] as $d)$p->prepare('DELETE FROM wmt_shifts WHERE work_date=?')->execute([$d]);foreach($j['tasks']??[] as $t){if(empty($t['name']))continue;$p->prepare('INSERT INTO wmt_tasks(name,category,priority,weight,frequency,notes) VALUES(?,?,?,?,?,?) ON DUPLICATE KEY UPDATE category=VALUES(category),priority=VALUES(priority),weight=VALUES(weight),frequency=VALUES(frequency),notes=VALUES(notes),active=1')->execute([$t['name'],$t['category']??'Entrance Readiness',$t['priority']??'Medium',(int)($t['weight']??2),$t['frequency']??'Daily',$t['notes']??null]);}foreach($j['schedule']??[] as $s){$d=$s['date']??$s['work_date']??'';$n=$s['name']??$s['associate_name']??'';if(!$d||!$n)continue;$id=upAssoc($p,['name'=>$n,'team'=>$s['team']??'Services','role_type'=>$s['role_type']??'AP Service TA','preferred_door'=>$s['preferred_door']??'Either']);$p->prepare('INSERT INTO wmt_shifts(work_date,associate_id,associate_name,team,role_type,start_time,end_time,notes) VALUES(?,?,?,?,?,?,?,?)')->execute([$d,$id,$n,$s['team']??'Services',$s['role_type']??'AP Service TA',$s['start']??$s['start_time'],$s['end']??$s['end_time'],$s['notes']??null]);}return'Import complete';}if($f==='csv'){$lines=preg_split('/\r\n|\n|\r/',trim($_POST['csv']??''));$h=array_map(fn($x)=>strtolower(trim($x)),str_getcsv(array_shift($lines)));$c=0;foreach($lines as $line){if(!trim($line))continue;$v=str_getcsv($line);$r=[];foreach($h as $i=>$k)$r[$k]=$v[$i]??'';$id=upAssoc($p,['name'=>$r['name']??'','team'=>$r['team']??'Services','role_type'=>$r['role_type']??'AP Service TA','preferred_door'=>$r['preferred_door']??'Either']);if($id){$p->prepare('INSERT INTO wmt_shifts(work_date,associate_id,associate_name,team,role_type,start_time,end_time,notes) VALUES(?,?,?,?,?,?,?,?)')->execute([$r['date'],$id,$r['name'],$r['team']??'Services',$r['role_type']??'AP Service TA',$r['start'],$r['end'],$r['notes']??null]);$c++;}}return"Imported $c CSV rows";}if($f==='turnin'){foreach($_POST['task']??[] as $r)$p->prepare('INSERT INTO wmt_turnins(work_date,task_name,status,completed_by,notes,manager_signoff) VALUES(?,?,?,?,?,?)')->execute([$_POST['date'],$r['name'],$r['status'],$r['by'],$r['notes'],$_POST['mgr']??null]);if(trim($_POST['exceptions']??''))$p->prepare("INSERT INTO wmt_exceptions(work_date,type,severity,notes,reported_to) VALUES(?,'Daily note','Medium',?,?)")->execute([$_POST['date'],$_POST['exceptions'],$_POST['mgr']??null]);return'Saved turn-in';}return'';}
function head($t){?><!doctype html><meta name=viewport content="width=device-width,initial-scale=1"><title><?=e($t)?></title><style>body{margin:0;background:#f4f1ea;color:#172019;font-family:system-ui}.top{background:#223b2a;color:white}.wrap{max-width:1220px;margin:auto;padding:18px}.nav a{color:white;margin-right:14px;font-weight:800;text-decoration:none}.card{background:white;border:1px solid #ddd2bf;border-radius:16px;padding:16px;margin:14px 0}.grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px}.kpi{background:#fff8ea;border:1px solid #ddd2bf;border-radius:12px;padding:12px}.kpi b{font-size:28px;display:block}.bad{color:#a32016;font-weight:900}.ok{color:#18632d;font-weight:900}.muted{color:#666}table{width:100%;border-collapse:collapse;background:white}td,th{border:1px solid #ddd;padding:7px;text-align:left;vertical-align:top}th{background:#f1eadc;font-size:12px;text-transform:uppercase}textarea{width:100%;min-height:160px}input,select,button,.btn{padding:9px;border-radius:9px;border:1px solid #bbb}button,.btn{background:#223b2a;color:white;font-weight:800;text-decoration:none}.no-print{}@media(max-width:800px){.grid{grid-template-columns:1fr}}@media print{.top,.no-print{display:none}.wrap{max-width:none}.card{border:0;margin:0 0 10px;padding:0;break-inside:avoid}body{background:white;font-size:12px}td,th{padding:5px}.page{break-before:page}}</style><div class="top no-print"><div class=wrap><b>AP Services Tool</b><div class=nav><a href=index.php>Dashboard</a><a href="?v=week">Week</a><a href="?v=import">Import</a><a href="?v=turnin">Turn-In</a><a href="?export=json">Export</a><a href="?logout=1">Logout</a></div></div></div><main class=wrap><?php }function foot(){?></main><?php}
function shiftTable($pl){?><div class=card><h2>Who is here</h2><table><tr><th>Name</th><th>Team</th><th>Role</th><th>Shift</th><th>Break/Lunch Plan</th><th>Preferred Door</th></tr><?php foreach($pl['sh'] as $s){$b=[];foreach(breaks($s) as $w)$b[]=$w[0].' '.nice((int)$w[1]).'-'.nice((int)($w[1]+$w[2]));?><tr><td><b><?=e($s['associate_name'])?></b></td><td><?=e($s['team'])?></td><td><?=e($s['role_type'])?></td><td><?=e(substr($s['start_time'],0,5))?>-<?=e(substr($s['end_time'],0,5))?></td><td><?=e(implode('; ',$b)?:'None planned')?></td><td><?=e($s['preferred_door']??'Either')?></td></tr><?php }?></table></div><?php}
function planTable($pl){?><div class=card><h2>8AM-5PM Coverage Plan</h2><table><tr><th>Time</th><th>Grocery</th><th>GM</th><th>Break/Lunch</th><th>Floater/Tasks</th><th>Flex</th><th>Watch</th></tr><?php foreach($pl['rows'] as $r){?><tr><td><?=nice($r[0])?>-<?=nice($r[1])?></td><td><?= $r[2]?e($r[2]):'<span class=bad>Uncovered</span>'?></td><td><?= $r[3]?e($r[3]):'<span class=bad>Uncovered</span>'?></td><td><?=e($r[5]?:'-')?></td><td><?=e($r[4]?:'-')?></td><td><?=e($r[6]?:'-')?></td><td><?= $r[7]?'<span class=bad>'.e($r[7]).'</span>':'<span class=ok>Covered</span>'?></td></tr><?php }?></table></div><?php}
function dash(PDO $p,$msg=''){$d=$_GET['date']??date('Y-m-d');$pl=plan($p,$d);head('Dashboard');if($msg)echo'<div class=card>'.e($msg).'</div>';?><div class="card no-print"><form><input type=date name=date value="<?=e($d)?>"><button>Load</button> <a class=btn href="?v=mgmt&date=<?=e($d)?>">Print Mgmt</a> <a class=btn href="?v=ta&date=<?=e($d)?>">Print TA</a> <a class=btn href="?v=turnin&date=<?=e($d)?>">Turn-In</a></form></div><div class=card><h1>Daily Coverage Review - <?=e($d)?></h1><p class=muted>Short-term target: both doors covered 8AM-5PM. Impossible gaps are shown, not forced.</p><div class=grid><div class=kpi>Coverage<b><?=e($pl['pct'])?>%</b></div><div class=kpi>Gap minutes<b class=<?= $pl['gap']?'bad':'ok'?>><?=e($pl['gap'])?></b></div><div class=kpi>Floater minutes<b><?=e($pl['float'])?></b></div><div class=kpi>Scheduled<b><?=count($pl['sh'])?></b></div></div></div><?php shiftTable($pl);planTable($pl);foot();}
function week(PDO $p){$d=new DateTime($_GET['date']??date('Y-m-d'));$d->modify('monday this week');head('Week');?><div class=card><h1>Weekly Summary</h1><table><tr><th>Date</th><th>Coverage</th><th>Gap</th><th>People</th><th>Print</th></tr><?php for($i=0;$i<7;$i++){$day=(clone$d)->modify("+$i day")->format('Y-m-d');$pl=plan($p,$day);?><tr><td><b><?=e($day)?></b></td><td><?=e($pl['pct'])?>%</td><td class=<?= $pl['gap']?'bad':'ok'?>><?=e($pl['gap'])?></td><td><?=count($pl['sh'])?></td><td><a href="?v=mgmt&date=<?=$day?>">Mgmt</a> · <a href="?v=ta&date=<?=$day?>">TA</a> · <a href="?v=turnin&date=<?=$day?>">Turn-in</a></td></tr><?php }?></table></div><?php foot();}
function importPage(PDO $p,$msg){head('Import');if($msg)echo'<div class=card>'.e($msg).'</div>';?><div class=card><h1>Import data</h1><p>Paste JSON from ChatGPT, or CSV with header: date,name,team,role_type,start,end,preferred_door,notes</p></div><div class=card><h2>JSON</h2><form method=post><input type=hidden name=form value=json><textarea name=payload>{
  "replace_schedule_dates":["2026-06-15"],
  "associates":[{"name":"Example TA","team":"Services","role_type":"AP Service TA","preferred_door":"Grocery"}],
  "schedule":[{"date":"2026-06-15","name":"Example TA","team":"Services","role_type":"AP Service TA","start":"08:00","end":"17:00","preferred_door":"Grocery"}]
}</textarea><button>Import JSON</button></form></div><div class=card><h2>CSV</h2><form method=post><input type=hidden name=form value=csv><textarea name=csv>date,name,team,role_type,start,end,preferred_door,notes
2026-06-15,Example TA,Services,AP Service TA,08:00,17:00,Grocery,</textarea><button>Import CSV</button></form></div><?php foot();}
function turnin(PDO $p,$msg=''){$d=$_GET['date']??date('Y-m-d');$tasks=$p->query('SELECT * FROM wmt_tasks WHERE active=1 ORDER BY FIELD(priority,"Critical","High","Medium","Low"),weight DESC,name')->fetchAll();head('Turn-In');if($msg)echo'<div class=card>'.e($msg).'</div>';?><div class=card><h1>Daily Turn-In / Sign-Off - <?=e($d)?></h1><form method=post><input type=hidden name=form value=turnin><input type=hidden name=date value="<?=e($d)?>"><table><tr><th>Task</th><th>Status</th><th>Completed By</th><th>Notes</th></tr><?php foreach($tasks as $i=>$t){?><tr><td><b><?=e($t['name'])?></b><br><span class=muted><?=e($t['category'].' · '.$t['priority'])?></span><input type=hidden name="task[<?=$i?>][name]" value="<?=e($t['name'])?>"></td><td><select name="task[<?=$i?>][status]"><option>Not Started</option><option>Completed</option><option>Missed</option><option>Deferred</option><option>N/A</option></select></td><td><input name="task[<?=$i?>][by]"></td><td><input name="task[<?=$i?>][notes]"></td></tr><?php }?></table><p>Exceptions / weather / door gaps / suspicious activity / equipment issues<br><textarea name=exceptions></textarea></p><p>Manager sign-off <input name=mgr></p><button class=no-print>Save</button></form></div><?php foot();}
function mgmt(PDO $p){$d=$_GET['date']??date('Y-m-d');$pl=plan($p,$d);head('Management Print');?><div class=card><h1>Management Daily Coverage Review - <?=e($d)?></h1><p><b>Rules:</b> Services own doors. Ops flex only when two Ops are available and not 10AM-12PM. TL max 15 minutes/day. Investigator never flexes. Tasks only after coverage and breaks/lunches are protected.</p><p><b>Coverage:</b> <?=e($pl['pct'])?>% · <b>Gap minutes:</b> <?=e($pl['gap'])?> · <b>Floater minutes:</b> <?=e($pl['float'])?></p></div><?php shiftTable($pl);planTable($pl);foot();}
function ta(PDO $p){$d=$_GET['date']??date('Y-m-d');$pl=plan($p,$d);head('TA Print');$names=[];foreach($pl['sh'] as $s)if(team($s)==='Services')$names[$s['associate_name']]=$s;foreach($names as $name=>$s){?><div class="card page"><h1>Associate Position Sheet - <?=e($name)?></h1><p><b>Date:</b> <?=e($d)?> <b>Shift:</b> <?=e(substr($s['start_time'],0,5))?>-<?=e(substr($s['end_time'],0,5))?></p><p><b>Do not leave your post until relieved or directed.</b> If relief does not arrive, contact leadership/AP.</p><table><tr><th>Time</th><th>Your Position</th><th>Handoff</th><th>Notes</th></tr><?php foreach($pl['rows'] as $r){$pos='';if($r[2]===$name)$pos='Grocery Door';elseif($r[3]===$name)$pos='GM Door';elseif($r[4]===$name)$pos='Task/Floater';elseif(str_contains($r[5],$name))$pos='Break/Lunch';if(!$pos)continue;?><tr><td><?=nice($r[0])?>-<?=nice($r[1])?></td><td><b><?=e($pos)?></b></td><td><?=str_contains($pos,'Door')?'Wait for assigned relief / leadership direction.':'Return to post at end of window.'?></td><td><?=e($r[7])?></td></tr><?php }?></table></div><?php }foot();}
try{$p=db();schema($p);auth($p);if(isset($_GET['export'])){header('Content-Type:application/json');echo json_encode(['settings'=>$p->query('SELECT * FROM wmt_settings')->fetchAll(),'associates'=>$p->query('SELECT * FROM wmt_associates')->fetchAll(),'schedule'=>$p->query('SELECT * FROM wmt_shifts ORDER BY work_date,start_time')->fetchAll(),'tasks'=>$p->query('SELECT * FROM wmt_tasks')->fetchAll()],JSON_PRETTY_PRINT);exit;}$msg=post($p);$v=$_GET['v']??'dashboard';if($v==='week')week($p);elseif($v==='import')importPage($p,$msg);elseif($v==='turnin')turnin($p,$msg);elseif($v==='mgmt')mgmt($p);elseif($v==='ta')ta($p);else dash($p,$msg);}catch(Throwable $e){http_response_code(500);echo'<pre>WMT setup error: '.e($e->getMessage()).'</pre>';}
